import (
    cuc "github.com/codeuchain/codeuchain/go"
)

validate := func(ctx *cuc.State) *cuc.State {
    if ctx.Get("age").(int) < 18 {
        ctx.Error = errors.New("too young")
    }
    return ctx
}

approve := func(ctx *cuc.State) *cuc.State {
    ctx.Set("status", "approved")
    return ctx
}

pipeline := cuc.Chain{}
pipeline.AddLink(cuc.NewLink("validate", validate))
pipeline.AddLink(cuc.NewLink("approve", approve))

result := pipeline.Execute(cuc.NewState(map[string]any{"age": 20}))
fmt.Println(result.Get("status"))
